 {"id":"bd-284","title":"Implement Identity Map for object caching","description":"# Task: Implement Identity Map for Object Caching

## Context
The Identity Map ensures that for any given primary key, there is exactly one object instance in the Session. This provides:
1. **Identity guarantee**: hero1 == hero2 if same PK
2. **Performance**: No redundant fetches for same object
3. **Consistency**: Changes to object seen everywhere

## What to Implement

### 1. ObjectKey
\`\`\`rust
use std::any::TypeId;
use std::hash::{Hash, Hasher};

/// Unique key for an object in the identity map.
#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash)]
pub struct ObjectKey {
    /// TypeId of the model (Hero, Team, etc.)
    type_id: TypeId,
    /// Hash of the primary key value(s)
    pk_hash: u64,
}

impl ObjectKey {
    pub fn new<T: Model>(pk: &[Value]) -> Self {
        let type_id = TypeId::of::<T>();
        let pk_hash = Self::hash_pk(pk);
        Self { type_id, pk_hash }
    }

    pub fn from<T: Model>(obj: &T) -> Self {
        let pk_values = obj.primary_key_value();
        Self::new::<T>(&pk_values)
    }

    fn hash_pk(pk: &[Value]) -> u64 {
        use std::collections::hash_map::DefaultHasher;
        let mut hasher = DefaultHasher::new();
        for v in pk {
            v.hash(&mut hasher);
        }
        hasher.finish()
    }
}
\`\`\`

### 2. TrackedObject
\`\`\`rust
use std::any::Any;

pub struct TrackedObject {
    /// Type-erased object
    object: Box<dyn Any + Send + Sync>,
    /// Snapshot for dirty detection (serialized bytes)
    original_state: Option<Vec<u8>>,
    /// Current tracking state
    state: ObjectState,
}

impl TrackedObject {
    pub fn new<T: Model + 'static>(obj: T, state: ObjectState) -> Self {
        let original = if state == ObjectState::Persistent {
            Some(Self::snapshot(&obj))
        } else {
            None
        };
        Self {
            object: Box::new(obj),
            original_state: original,
            state,
        }
    }

    pub fn get<T: 'static>(&self) -> Option<&T> {
        self.object.downcast_ref()
    }

    pub fn get_mut<T: 'static>(&mut self) -> Option<&mut T> {
        self.object.downcast_mut()
    }

    fn snapshot<T: Serialize>(obj: &T) -> Vec<u8> {
        serde_json::to_vec(obj).unwrap_or_default()
    }
}
\`\`\`

### 3. IdentityMap
\`\`\`rust
use std::collections::HashMap;

pub struct IdentityMap {
    objects: HashMap<ObjectKey, TrackedObject>,
}

impl IdentityMap {
    pub fn new() -> Self {
        Self { objects: HashMap::new() }
    }

    pub fn get<T: Model + 'static>(&self, pk: &[Value]) -> Option<&T> {
        let key = ObjectKey::new::<T>(pk);
        self.objects.get(&key)?.get::<T>()
    }

    pub fn insert<T: Model + 'static>(&mut self, obj: T, state: ObjectState) {
        let key = ObjectKey::from(&obj);
        let tracked = TrackedObject::new(obj, state);
        self.objects.insert(key, tracked);
    }

    pub fn remove(&mut self, key: &ObjectKey) -> Option<TrackedObject> {
        self.objects.remove(key)
    }

    pub fn contains(&self, key: &ObjectKey) -> bool {
        self.objects.contains_key(key)
    }

    pub fn len(&self) -> usize { self.objects.len() }

    pub fn iter(&self) -> impl Iterator<Item = (&ObjectKey, &TrackedObject)> {
        self.objects.iter()
    }
}
